const body = $input.first().json.body || $input.first().json;
const db06_id = (body.db06_id || body.id || '').toString().replace(/-/g, '');
if (!db06_id) throw new Error('missing db06_id');
return [{ json: { db06_id } }];

const p = $input.first().json;
const TARGET_RELS = ["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"];
let target_id = '', target_rel = '';
for (const rel of TARGET_RELS) {
  const arr = p.properties[rel]?.relation || [];
  if (arr.length) { target_id = (arr[0].id||'').replace(/-/g,''); target_rel = rel; break; }
}
return [{ json: {
  db06_id: p.id.replace(/-/g, ''),
  ai_mode: p.properties['ai模式']?.select?.name || '',
  execute_idea_db06: p.properties['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '',
  mingxi_content: p.properties['明細內容']?.rich_text?.map(t=>t.plain_text).join('') || '',
  db05_id: target_id,
  target_rel: target_rel,
  mingxi_name: p.properties['明細名稱']?.title?.map(t=>t.plain_text).join('') || '',
  sort_num: p.properties['排序']?.number
}}];

const baton = $('Parse DB06').first().json;
const target = $input.first().json;
const tp = target.properties || {};
const NHEAD={'Authorization':'Bearer '+$env.NOTION_INTEGRATION_TOKEN,'Notion-Version':'2022-06-28','Content-Type':'application/json'};
const norm=id=>(id||'').replace(/-/g,'');
const withTO=(p,ms)=>Promise.race([p,new Promise((_,r)=>setTimeout(()=>r(new Error('to')),ms))]);
const sleep=ms=>new Promise(r=>setTimeout(r,ms));
const getPage=async id=>{try{const r=await withTO(this.helpers.httpRequest({method:'GET',url:'https://api.notion.com/v1/pages/'+id,headers:NHEAD}),10000);return (typeof r==='string')?JSON.parse(r):r;}catch(e){return null;}};
const titleProp=Object.values(tp).find(v=>v&&v.type==='title');
const target_name=(titleProp?.title||[]).map(t=>t.plain_text).join('')||'(未命名)';
const rt=k=>(tp[k]?.rich_text||[]).map(t=>t.plain_text).join('');
const cur_idea=rt('執行構想');
const summary=rt('簡介摘要');
const analysis=rt('分析備註');
const tgt_exec_note=rt('執行備註')||'';
const copyType=tp['文案選項']?.select?.name||'';
const XF=['提案引用','管考引用','項目引用','協作引用','內容引用','明細引用','庫存引用','對象引用','日期引用'];
let refIds=[];for(const f of XF){for(const r of ((tp[f]&&tp[f].relation)||[]))refIds.push(norm(r.id));}
refIds=[...new Set(refIds)].slice(0,30);
let refs=[];
for(let i=0;i<refIds.length;i+=4){const part=await Promise.all(refIds.slice(i,i+4).map(getPage));for(const pg of part){if(!pg)continue;const pt=Object.values(pg.properties||{}).find(v=>v&&v.type==='title');const nm=(pt?.title||[]).map(t=>t.plain_text).join('');const mc=((pg.properties||{})['明細內容']?.rich_text||[]).map(t=>t.plain_text).join('');const sm=((pg.properties||{})['簡介摘要']?.rich_text||[]).map(t=>t.plain_text).join('');if(nm||mc||sm)refs.push('・'+nm+(mc||sm?('：'+(mc||sm).slice(0,200)):''));}if(i+4<refIds.length)await sleep(320);}
const system="你是 makesense（現思文化創藝有限公司，宜蘭在地文化事業）嗨嗨家族的嗨嗨文案。職責：依 target 的執行構想（內含企劃寫好的章節架構）寫出 target 的頁面正文。
== 鐵律 ==
1. 執行構想是最高指示：企劃已把內容拆成數個 ## 章節、每章標了目標字數與素材方向。逐章寫，章節數與標題對齊執行構想，不增不減。
2. 每章字數對齊執行構想標的目標字數。
3. 具體可查證：用具名事件/日期/人物/數字/地點。嚴禁堆疊沒有實據的空泛形容詞（氛圍詞）。
4. 素材未齊的部分（執行構想標「待補」者）：就現有素材能寫多少寫多少，不硬編數字、不杜撰，可寫「此部分待補」帶過，不要假裝有資料。
5. 一律繁體中文。正文用 markdown：章節標題用 ## 開頭，內文分段。
== 輸出 只回合法 JSON ==
{"execution_summary":"寫了什麼、總字數、依幾章","page_content":"完整正文 markdown，## 章節標題 + 內文段落","needs_human_intervention":false}";
const user='target 名稱：'+target_name+'
文案類型：'+(copyType||'(未指定)')+'

【執行構想 — 企劃寫好的章節架構，逐章照寫】
'+(cur_idea||'(空)')+'

【簡介摘要】
'+(summary||'(空)')+'

【分析備註 — 嗨嗨分析鑑定的重點與數據】
'+(analysis||'(空)')+'

【參考資料 '+refs.length+' 筆（X引用的 DB06 資料參考）】
'+(refs.join('
')||'(無)')+'

【上輪嗨嗨檢核成果紀錄】
'+(tgt_exec_note||'(尚未有檢核記錄)')+'

依執行構想的章節架構逐章寫正文，回 JSON。';
return [{json:{system,user,target_name,target_id:baton.db05_id,db06_id:baton.db06_id,ai_mode:baton.ai_mode||'文案',sort_num:baton.sort_num,ref_count:refs.length,target_rel:baton.target_rel}}];

const resp = $input.first().json;
const ctx = $('Build Claude prompt').first().json;
const text = resp.content?.[0]?.text || '';
const usage = resp.usage || {};
let p; try { const m=text.match(/\{[\s\S]*\}/); p=m?JSON.parse(m[0]):{} } catch(e){ p={} }
const md = (p.page_content||'').toString();

// 行內粗體 **text**
const inlineRich = (s) => {
  s=(s||'').toString(); const out=[];
  for (const seg of s.split(/(\*\*[^*]+\*\*)/g)) {
    if(!seg) continue;
    const b=seg.match(/^\*\*([^*]+)\*\*$/);
    if(b) out.push({text:{content:b[1].slice(0,2000)},annotations:{bold:true}});
    else out.push({text:{content:seg.slice(0,2000)}});
  }
  return out.length?out:[{text:{content:''}}];
};

const lines = md.split('\n');
const blocks = []; let para = []; let tableRows = null;
const flushPara = () => { if(para.length){ const txt=para.join('\n').trim(); if(txt){ for(let i=0;i<txt.length;i+=2000) blocks.push({object:'block',type:'paragraph',paragraph:{rich_text:inlineRich(txt.slice(i,i+2000))}}); } para=[]; } };
const flushTable = () => {
  if(tableRows && tableRows.length){
    const width=Math.max(...tableRows.map(r=>r.length));
    const rowBlocks=tableRows.map(cells=>{ const c=cells.slice(); while(c.length<width)c.push(''); return {object:'block',type:'table_row',table_row:{cells:c.map(x=>inlineRich(x))}}; });
    blocks.push({object:'block',type:'table',table:{table_width:width,has_column_header:true,has_row_header:false,children:rowBlocks}});
  }
  tableRows=null;
};
const isRow = ln => /^\s*\|.*\|\s*$/.test(ln);
const isSep = ln => /-/.test(ln) && /^\s*\|?[\s:|-]+\|?\s*$/.test(ln);
const splitRow = ln => { let s=ln.trim(); if(s.startsWith('|'))s=s.slice(1); if(s.endsWith('|'))s=s.slice(0,-1); return s.split('|').map(c=>c.trim()); };

for (const ln of lines) {
  if (isRow(ln)) { if(isSep(ln)) continue; flushPara(); if(!tableRows)tableRows=[]; tableRows.push(splitRow(ln)); continue; }
  if (tableRows) flushTable();
  const h3=ln.match(/^###\s+(.+)/), h2=ln.match(/^##\s+(.+)/), h1=ln.match(/^#\s+(.+)/);
  const bul=ln.match(/^\s*[-*]\s+(.+)/), num=ln.match(/^\s*\d+\.\s+(.+)/), quo=ln.match(/^>\s?(.*)/);
  if(h3){flushPara();blocks.push({object:'block',type:'heading_3',heading_3:{rich_text:inlineRich(h3[1])}});}
  else if(h2){flushPara();blocks.push({object:'block',type:'heading_2',heading_2:{rich_text:inlineRich(h2[1])}});}
  else if(h1){flushPara();blocks.push({object:'block',type:'heading_1',heading_1:{rich_text:inlineRich(h1[1])}});}
  else if(bul){flushPara();blocks.push({object:'block',type:'bulleted_list_item',bulleted_list_item:{rich_text:inlineRich(bul[1])}});}
  else if(num){flushPara();blocks.push({object:'block',type:'numbered_list_item',numbered_list_item:{rich_text:inlineRich(num[1])}});}
  else if(quo && ln.trim().startsWith('>')){flushPara();blocks.push({object:'block',type:'quote',quote:{rich_text:inlineRich(quo[1])}});}
  else if(ln.trim()===''){flushPara();}
  else para.push(ln);
}
flushPara(); if(tableRows) flushTable();

const children = blocks; // 不再 slice(0,100)；寫入正文(乙) 本來就 50 塊一批
const wordCount = md.replace(/\s/g,'').length;
const it=parseInt(usage.input_tokens||0), ot=parseInt(usage.output_tokens||0);
const cost=((it*3+ot*15)/1000000*32).toFixed(2);
const usage_line='進='+it+' 出='+ot+' 成本NT'+cost;
const d=new Date(); const tw=new Date(d.getTime()+8*3600*1000);
const ts=tw.getUTCFullYear()+'-'+String(tw.getUTCMonth()+1).padStart(2,'0')+'-'+String(tw.getUTCDate()).padStart(2,'0')+' '+String(tw.getUTCHours()).padStart(2,'0')+':'+String(tw.getUTCMinutes()).padStart(2,'0');
const chapters = blocks.filter(b=>b.type==='heading_1'||b.type==='heading_2'||b.type==='heading_3').length;
const exec_summary=(p.execution_summary||'文案完成').toString();
const exec_note=('── '+ts+' 文案 ──\n工作對象：'+ctx.target_name+'\n做了什麼：寫 target 頁面正文 約 '+wordCount+' 字、'+chapters+' 章節\n參考資料：'+ctx.ref_count+' 筆\n'+exec_summary).slice(0,1990);
const sanitize=s=>(s||'').toString().replace(/[\/\\:<>#@\[\]\{\}\|\^`\*_~"']/g,' ').replace(/\s+/g,' ').trim().slice(0,500);
const pub_props = (ctx.target_rel==='對應內容') ? {'發佈狀態':{status:{name:'待發佈'}}} : {};
return [{ json: { db06_id:ctx.db06_id, db05_id:ctx.target_id, target_id:ctx.target_id, ai_mode:ctx.ai_mode, sort_num:ctx.sort_num, pub_props, children, has_content: children.length>0, word_count:wordCount, exec_note, usage_line, safe_summary:sanitize(exec_note), preview_text:'文案寫入 '+wordCount+' 字 / '+children.length+' blocks', validator_warning:'' } }];

const pc = $('Parse Claude').first().json;
const NHEAD = {'Authorization':'Bearer '+$env.NOTION_INTEGRATION_TOKEN,'Notion-Version':'2022-06-28','Content-Type':'application/json'};
const target = pc.target_id;
const newBlocks = pc.children || [];
const HTYPES = ['heading_1','heading_2','heading_3','paragraph'];
let old = [];
try {
  let cursor, guard=0;
  do {
    const u='https://api.notion.com/v1/blocks/'+target+'/children?page_size=100'+(cursor?('&start_cursor='+cursor):'');
    const r=await this.helpers.httpRequest({method:'GET',url:u,headers:NHEAD});
    const rr=(typeof r==='string')?JSON.parse(r):r;
    for(const b of (rr.results||[])) old.push(b);
    cursor=rr.has_more?rr.next_cursor:null; guard++;
  } while(cursor&&guard<12);
} catch(e){}
const recreate = b => {
  const t=b.type;
  if(HTYPES.indexOf(t)<0) return null;
  const rt=((b[t]||{}).rich_text||[]).map(x=>({text:{content:(x.plain_text||'').slice(0,2000)}}));
  return {object:'block',type:t,[t]:{rich_text:rt.length?rt:[{text:{content:''}}]}};
};
const oldSpecs = old.map(recreate).filter(Boolean);
const appendBatch = async (blocks) => {
  for(let i=0;i<blocks.length;i+=50){
    await this.helpers.httpRequest({method:'PATCH',url:'https://api.notion.com/v1/blocks/'+target+'/children',headers:NHEAD,body:JSON.stringify({children:blocks.slice(i,i+50)})});
  }
};
let note='';
try {
  await appendBatch(newBlocks);
  if (oldSpecs.length) {
    await appendBatch([{object:'block',type:'divider',divider:{}},{object:'block',type:'paragraph',paragraph:{rich_text:[{text:{content:'── 以下為前一版（舊）──'}}]}}]);
    await appendBatch(oldSpecs);
    for (const b of old) {
      try { await this.helpers.httpRequest({method:'DELETE',url:'https://api.notion.com/v1/blocks/'+b.id.replace(/-/g,''),headers:NHEAD}); } catch(e){}
    }
    note='新版已寫入頁面最上方，前一版 '+oldSpecs.length+' 塊已移到下方保留';
  } else {
    note='頁面原為空，新版已寫入';
  }
} catch(err){ note='寫入正文錯誤：'+(err&&err.message||err); }
return [{ json: { ...pc, write_note: note } }];

const row=$input.first().json||{};
const pc=$('Parse Claude').first().json;
const auto_mode=row.auto_mode===true;
const reply_to=parseInt(row.last_msg_id||0)||0;
const result_msg='✅ 第 '+(pc.sort_num!=null?pc.sort_num:'?')+' 棒 ('+(pc.ai_mode||'')+') 已完成
DB06 '+pc.db06_id+'

'+(pc.safe_summary||'')+(pc.usage_line?('
tokens '+pc.usage_line):'')+'

📄 target 頁面：https://www.notion.so/'+(pc.db05_id||'').replace(/-/g,'');
return [{json:{auto_mode,reply_to,flow_id:pc.db05_id,db05_id:pc.db05_id,db06_id:pc.db06_id,sort_num:pc.sort_num,ai_mode:pc.ai_mode,result_msg}}];

